<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***AdvancedSearchEngineforSPRIN*Full-textsearchwithmultiplefilters*/classAdvancedSearch{private$db;private$searchableFields=['personil'=>['fields'=>['nama','nrp','gelar_pendidikan','status_ket'],'joins'=>['pangkat'=>['field'=>'nama_pangkat','fk'=>'id_pangkat'],'jabatan'=>['field'=>'nama_jabatan','fk'=>'id_jabatan'],'bagian'=>['field'=>'nama_bagian','fk'=>'id_bagian'],'unsur'=>['field'=>'nama_unsur','fk'=>'id_unsur']]]];publicfunction__construct(){require_once__DIR__.'/Database.php';$this->db=Database::getInstance();}/***Performadvancedsearchonpersonil*/publicfunctionsearchPersonil($query,$filters=[],$options=[]){$limit=$options['limit']??100;$offset=$options['offset']??0;$sortBy=$options['sort_by']??'nama';$sortOrder=$options['sort_order']??'ASC';/Buildbasequery$sql="SELECTp.id,p.nama,p.nama_lengkap,p.gelar_pendidikan,p.nrp,p.JK,p.status_ket,p.status_nikah,p.tanggal_lahir,p.tempat_lahir,mjp.nama_jenisasstatus_kepegawaian,mjp.kode_jenisaskode_kepegawaian,pg.nama_pangkat,pg.singkatanaspangkat_singkatan,j.nama_jabatan,b.nama_bagian,u.nama_unsur,u.kode_unsur,p.created_at,p.updated_atFROMpersonilpLEFTJOINmaster_jenis_pegawaimjpONp.id_jenis_pegawai=mjp.idLEFTJOINpangkatpgONp.id_pangkat=pg.idLEFTJOINjabatanjONp.id_jabatan=j.idLEFTJOINbagianbONp.id_bagian=b.idLEFTJOINunsuruONp.id_unsur=u.idWHEREp.is_deleted=falseANDp.is_active=true";$params=[];$whereConditions=[];/Full-textsearchif(!empty($query)){$searchTerm="%{$query}%";$whereConditions[]="(p.namaLIKE:searchORp.nrpLIKE:searchORp.gelar_pendidikanLIKE:searchORp.status_ketLIKE:searchORpg.nama_pangkatLIKE:searchORpg.singkatanLIKE:searchORj.nama_jabatanLIKE:searchORb.nama_bagianLIKE:searchORu.nama_unsurLIKE:search)";$params['search']=$searchTerm;}/Applyfiltersif(!empty($filters['unsur'])){$whereConditions[]="u.kode_unsur=:unsur";$params['unsur']=$filters['unsur'];}if(!empty($filters['bagian'])){$whereConditions[]="b.id=:bagian";$params['bagian']=$filters['bagian'];}if(!empty($filters['pangkat'])){$whereConditions[]="pg.id=:pangkat";$params['pangkat']=$filters['pangkat'];}if(!empty($filters['jabatan'])){$whereConditions[]="j.id=:jabatan";$params['jabatan']=$filters['jabatan'];}if(!empty($filters['jenis_pegawai'])){$whereConditions[]="mjp.kode_jenis=:jenis_pegawai";$params['jenis_pegawai']=$filters['jenis_pegawai'];}if(!empty($filters['jk'])){$whereConditions[]="p.JK=:jk";$params['jk']=$filters['jk'];}if(!empty($filters['status_nikah'])){$whereConditions[]="p.status_nikah=:status_nikah";$params['status_nikah']=$filters['status_nikah'];}/Daterangefiltersif(!empty($filters['tanggal_lahir_from'])){$whereConditions[]="p.tanggal_lahir>=:tanggal_lahir_from";$params['tanggal_lahir_from']=$filters['tanggal_lahir_from'];}if(!empty($filters['tanggal_lahir_to'])){$whereConditions[]="p.tanggal_lahir<=:tanggal_lahir_to";$params['tanggal_lahir_to']=$filters['tanggal_lahir_to'];}/AddwhereconditionstoSQLif(!empty($whereConditions)){$sql.="AND".implode("AND",$whereConditions);}/Gettotalcount$countSql="SELECTCOUNT(*)astotalFROM({$sql})ascount_table";$totalResult=$this->db->fetchOne($countSql,$params);$total=$totalResult['total']??0;/Addsorting$allowedSortFields=['nama','nrp','tanggal_lahir','created_at'];$sortField=in_array($sortBy,$allowedSortFields)?"p.{$sortBy}":'p.nama';$sortDirection=strtoupper($sortOrder)==='DESC'?'DESC':'ASC';$sql.="ORDERBY{$sortField}{$sortDirection}";/Addpagination$sql.="LIMIT:limitOFFSET:offset";$params['limit']=$limit;$params['offset']=$offset;/Executequery$results=$this->db->fetchAll($sql,$params);/Enhanceresultswithhighlights$enhancedResults=[];forforeach($resultsas$row){$highlighted=$this->highlightSearchTerms($row,$query);$enhancedResults[]=$highlighted;}return['data'=>$enhancedResults,'pagination'=>['total'=>$total,'limit'=>$limit,'offset'=>$offset,'current_page'=>floor($offset/$limit)+1,'total_pages'=>ceil($total/$limit),'has_next'=>($offset+$limit)<$total,'has_prev'=>$offset>0],'filters_applied'=>$filters,'search_query'=>$query];}/***Highlightsearchtermsinresults*/privatefunctionhighlightSearchTerms($row,$query){if(empty($query)){return$row;}$highlightFields=['nama','nrp','gelar_pendidikan','status_ket','nama_pangkat','nama_jabatan','nama_bagian','nama_unsur'];$highlighted=[];forforeach($rowas$key=>$value){if(in_array($key,$highlightFields)&&is_string($value)){$pattern='/('.preg_quote($query,'/').')/i';$highlighted[$key.'_highlighted']=preg_replace($pattern,'<mark>$1</mark>',htmlspecialchars($value));}$highlighted[$key]=$value;}return$highlighted;}/***Getsearchsuggestions*/publicfunctiongetSuggestions($query,$limit=10){if(empty($query)||strlen($query)<2){return[];}$searchTerm="%{$query}%";$sql="SELECTDISTINCTnamaassuggestion,'nama'astypeFROMpersonilWHEREis_deleted=falseANDnamaLIKE:searchLIMIT:limit";$results=$this->db->fetchAll($sql,['search'=>$searchTerm,'limit'=>$limit]);return$results;}/***Quicksearch(forlivesearch)*/publicfunctionquickSearch($query,$limit=20){if(empty($query)){return[];}$searchTerm="%{$query}%";$sql="SELECTp.id,p.nama,p.nama_lengkap,p.nrp,pg.singkatanaspangkat_singkatan,j.nama_jabatan,b.nama_bagian,u.nama_unsurFROMpersonilpLEFTJOINpangkatpgONp.id_pangkat=pg.idLEFTJOINjabatanjONp.id_jabatan=j.idLEFTJOINbagianbONp.id_bagian=b.idLEFTJOINunsuruONp.id_unsur=u.idWHEREp.is_deleted=falseANDp.is_active=trueAND(p.namaLIKE:searchORp.nrpLIKE:searchORp.gelar_pendidikanLIKE:search)ORDERBYp.namaLIMIT:limit";return$this->db->fetchAll($sql,['search'=>$searchTerm,'limit'=>$limit]);}/***Getavailablefilters*/publicfunctiongetAvailableFilters(){$filters=[];/Unsuroptions$filters['unsur']=$this->db->fetchAll("SELECTid,kode_unsur,nama_unsurFROMunsurWHEREis_active=trueORDERBYurutan");/Bagianoptions$filters['bagian']=$this->db->fetchAll("SELECTid,nama_bagian,id_unsurFROMbagianWHEREis_active=trueORDERBYnama_bagian");/Pangkatoptions$filters['pangkat']=$this->db->fetchAll("SELECTid,nama_pangkat,singkatanFROMpangkatORDERBYlevel_pangkat");/Jabatanoptions$filters['jabatan']=$this->db->fetchAll("SELECTid,nama_jabatanFROMjabatanORDERBYnama_jabatan");/Jenispegawaioptions$filters['jenis_pegawai']=$this->db->fetchAll("SELECTid,kode_jenis,nama_jenisFROMmaster_jenis_pegawaiORDERBYkode_jenis");return$filters;}/***Searchwithautocomplete*/publicfunctionautocomplete($query,$field='nama',$limit=10){$allowedFields=['nama','nrp'];if(!in_array($field,$allowedFields)||empty($query)){return[];}$searchTerm="%{$query}%";$sql="SELECTDISTINCT{$field}asvalue,COUNT(*)asfrequencyFROMpersonilWHEREis_deleted=falseAND{$field}LIKE:searchGROUPBY{$field}ORDERBYfrequencyDESC,{$field}LIMIT:limit";return$this->db->fetchAll($sql,['search'=>$searchTerm,'limit'=>$limit]);}}?>
